module sr_latch (  
    input wire Anti_S,  
    input wire R,  
    output reg Q,  
    output wire Qn  
);  
    assign Qn = ~Q;  

    always @(Anti_S, R) begin  
        if (Anti_S && ~R)  
            Q <= 1'b1;  
        else if (~Anti_S && R)  
            Q <= 1'b0;  
        // If both Anti_S and R are low, keep the previous state (no action)  
    end  
endmodule
